const listUserSharedDashboards = `-- name: ListUserSharedDashboards :many
SELECT ds.id, ds.dashboard_id, ds.shared_with_user_id, ds.shared_with_role, ds.shared_with_workspace_id, ds.permission, ds.expires_at, ds.created_at, ds.created_by, ud.name as dashboard_name, ud.description, ud.layout
FROM dashboard_shares ds
JOIN user_dashboards ud ON ds.dashboard_id = ud.id
WHERE ds.shared_with_user_id = $1
  AND (ds.expires_at IS NULL OR ds.expires_at > NOW())
ORDER BY ds.created_at DESC
`

