const recordDashboardView = `-- name: RecordDashboardView :one

INSERT INTO dashboard_views (
    dashboard_id, user_id, session_id, source, device_type
) VALUES ($1, $2, $3, $4, $5)
RETURNING id, dashboard_id, user_id, viewed_at, session_id, duration_seconds, widget_interactions, source, device_type
`

type RecordDashboardViewParams struct {
	DashboardID pgtype.UUID `json:"dashboard_id"`
	UserID      string      `json:"user_id"`
	SessionID   *string     `json:"session_id"`
	Source      *string     `json:"source"`
	DeviceType  *string     `json:"device_type"`
}

// ============================================================================
// DASHBOARD VIEWS
// ============================================================================
func (q *Queries) RecordDashboardView(ctx context.Context, arg RecordDashboardViewParams) (DashboardView, error) {
	row := q.db.QueryRow(ctx, recordDashboardView,
		arg.DashboardID,
		arg.UserID,
		arg.SessionID,
		arg.Source,
		arg.DeviceType,
	)
	var i DashboardView
	err := row.Scan(
		&i.ID,
		&i.DashboardID,
		&i.UserID,
		&i.ViewedAt,
		&i.SessionID,
		&i.DurationSeconds,
		&i.WidgetInteractions,
		&i.Source,
		&i.DeviceType,
	)
	return i, err
}

const setWidgetCache = `-- name: SetWidgetCache :one
INSERT INTO widget_data_cache (user_id, widget_type, cache_key, data, expires_at)
VALUES ($1, $2, $3, $4, $5)
ON CONFLICT (user_id, widget_type, cache_key)
DO UPDATE SET 
    data = EXCLUDED.data, 
    expires_at = EXCLUDED.expires_at,
    created_at = NOW()
RETURNING id, user_id, widget_type, cache_key, data, expires_at, created_at, hit_count, last_hit_at
`

type SetWidgetCacheParams struct {
	UserID     string             `json:"user_id"`
	WidgetType string             `json:"widget_type"`
	CacheKey   string             `json:"cache_key"`
	Data       []byte             `json:"data"`
	ExpiresAt  pgtype.Timestamptz `json:"expires_at"`
}

func (q *Queries) SetWidgetCache(ctx context.Context, arg SetWidgetCacheParams) (WidgetDataCache, error) {
	row := q.db.QueryRow(ctx, setWidgetCache,
		arg.UserID,
		arg.WidgetType,
		arg.CacheKey,
		arg.Data,
		arg.ExpiresAt,
	)
	var i WidgetDataCache
	err := row.Scan(
		&i.ID,
		&i.UserID,
		&i.WidgetType,
		&i.CacheKey,
		&i.Data,
		&i.ExpiresAt,
		&i.CreatedAt,
		&i.HitCount,
		&i.LastHitAt,
	)
	return i, err
}

